interaction/computing-flows.text:
import { AfterViewInit, Component, ElementRef, viewChild } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/renderer-angular';
import { markReady } from '../demo-ready';

/** Data flowing through TYPED ports: type a value into the source and every
 *  downstream node recomputes LIVE along the real link topology; rewiring or
 *  cutting a wire recomputes off the new topology. Grafloria owns the graph and
 *  fires link:added / link:removed; the app owns the arithmetic. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  template: `
    <div id="readout" style="padding:8px 24px;font:12px/1.5 ui-monospace,monospace;opacity:.9;border-bottom:1px solid rgba(127,127,127,.25);display:flex;align-items:center;gap:14px;flex-wrap:wrap">
      <label style="display:inline-flex;align-items:center;gap:6px">input
        <input #src type="number" step="1" value="2" style="width:74px;font:inherit;padding:2px 6px;border:1px solid rgba(127,127,127,.5);border-radius:4px;background:transparent;color:inherit">
      </label>
      <span #formula style="white-space:pre"></span>
    </div>
    <grafloria-diagram-canvas [(nodes)]="nodes" [(edges)]="edges"
      style="display:block;height:calc(100vh - 44px)" />
  `,
})
export class ComputingFlowsComponent implements AfterViewInit {
  canvas = viewChild.required(DiagramCanvasComponent);
  src = viewChild.required<ElementRef<HTMLInputElement>>('src');
  formula = viewChild.required<ElementRef<HTMLElement>>('formula');
  nodes: any[] = [
    { id: 'in', position: { x: 40, y: 120 }, size: { width: 120, height: 56 }, label: 'input',
      ports: [{ id: 'in.out', side: 'right', type: 'output', dataType: 'number' }], data: { value: 2 } },
    { id: 'mul', position: { x: 240, y: 120 }, size: { width: 120, height: 56 }, label: '× 3',
      ports: [{ id: 'mul.in', side: 'left', type: 'input', dataType: 'number' },
              { id: 'mul.out', side: 'right', type: 'output', dataType: 'number' }], data: { op: 'mul', k: 3, value: 0 } },
    { id: 'add', position: { x: 440, y: 120 }, size: { width: 120, height: 56 }, label: '+ 10',
      ports: [{ id: 'add.in', side: 'left', type: 'input', dataType: 'number' },
              { id: 'add.out', side: 'right', type: 'output', dataType: 'number' }], data: { op: 'add', k: 10, value: 0 } },
    { id: 'out', position: { x: 640, y: 120 }, size: { width: 120, height: 56 }, label: 'sink',
      ports: [{ id: 'out.in', side: 'left', type: 'input', dataType: 'number' }], data: { op: 'sink', value: 0 } },
  ];
  edges: any[] = [
    { id: 'l1', source: 'in', target: 'mul', sourceHandle: 'in.out', targetHandle: 'mul.in' },
    { id: 'l2', source: 'mul', target: 'add', sourceHandle: 'mul.out', targetHandle: 'add.in' },
    { id: 'l3', source: 'add', target: 'out', sourceHandle: 'add.out', targetHandle: 'out.in' },
  ];

  ngAfterViewInit() {
    const model = this.canvas().activeEngine()?.getDiagram() as any;
    const srcInput = this.src().nativeElement;
    const formula = this.formula().nativeElement;
    if (!model) { markReady(); return; }

    const order = ['in', 'mul', 'add', 'out'];
    const propagate = () => {
      const incoming = (id: string) => model.getLinks().filter((l: any) => l.targetNodeId === id);
      for (const id of order) {
        if (id === 'in') continue;
        const node = model.getNode(id); if (!node) continue;
        const feeds = incoming(id);
        const input = feeds.length ? (model.getNode(feeds[0].sourceNodeId)?.data.value ?? 0) : null;
        if (input === null) continue;
        const d = node.data;
        d.value = d.op === 'mul' ? input * d.k : d.op === 'add' ? input + d.k : input;
      }
      const v = (id: string) => model.getNode(id)?.data.value ?? 0;
      formula.textContent = `→  ×3=${v('mul')}  →  +10=${v('add')}  →  sink=${v('out')}`;
      if (document.activeElement !== srcInput) srcInput.value = String(v('in'));
    };

    srcInput.addEventListener('input', () => {
      const n = Number(srcInput.value);
      const inN = model.getNode('in'); if (inN) inN.data.value = Number.isFinite(n) ? n : 0;
      propagate();
    });
    model.on?.('link:added', () => propagate());
    model.on?.('link:removed', () => propagate());

    propagate();
    markReady();
  }
}

interaction/connection-events.text:
import { AfterViewInit, Component, ElementRef, viewChild } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/renderer-angular';
import { markReady } from '../demo-ready';

/** A live log of the connection lifecycle the engine fires as you drag a wire —
 *  start, per-move update, port enter/leave, then complete or cancel. The stream
 *  splits the "end" into complete (valid) vs cancel (abandoned/refused). Wired by
 *  subscribing to the engine's eventBus, exactly the events a real drag fires. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  template: `
    <div style="padding:8px 24px 10px;border-bottom:1px solid rgba(127,127,127,.25);font:12px/1.4 ui-monospace,monospace">
      <div #flags style="display:flex;gap:8px;flex-wrap:wrap;align-items:center">
        <span class="flag" data-ev="connection:start" style="padding:2px 9px;border:1px solid rgba(127,127,127,.4);border-radius:999px;opacity:.32">start</span>
        <span class="flag" data-ev="connection:update" style="padding:2px 9px;border:1px solid rgba(127,127,127,.4);border-radius:999px;opacity:.32">update</span>
        <span class="flag" data-ev="connection:port-enter" style="padding:2px 9px;border:1px solid rgba(127,127,127,.4);border-radius:999px;opacity:.32">port-enter</span>
        <span class="flag" data-ev="connection:complete" style="padding:2px 9px;border:1px solid rgba(127,127,127,.4);border-radius:999px;opacity:.32">complete</span>
        <span class="flag" data-ev="connection:cancel" style="padding:2px 9px;border:1px solid rgba(127,127,127,.4);border-radius:999px;opacity:.32">cancel</span>
        <button #clear style="font:inherit;padding:2px 9px;border:1px solid rgba(127,127,127,.4);border-radius:6px;background:transparent;color:inherit;cursor:pointer">clear</button>
      </div>
      <div #log style="margin-top:8px;height:88px;overflow-y:auto;white-space:pre;opacity:.9"><span style="opacity:.5">drag from the source's right port to see the connection lifecycle fire…</span></div>
    </div>
    <grafloria-diagram-canvas [(nodes)]="nodes" [(edges)]="edges"
      style="display:block;height:calc(100vh - 150px);min-height:300px" />
  `,
})
export class ConnectionEventsComponent implements AfterViewInit {
  canvas = viewChild.required(DiagramCanvasComponent);
  flags = viewChild.required<ElementRef<HTMLElement>>('flags');
  log = viewChild.required<ElementRef<HTMLElement>>('log');
  clear = viewChild.required<ElementRef<HTMLButtonElement>>('clear');
  nodes: any[] = [
    { id: 'src', position: { x: 80, y: 70 }, size: { width: 150, height: 60 }, label: 'source',
      ports: [{ id: 'src.out', side: 'right', type: 'output' }] },
    { id: 'dst', position: { x: 430, y: 70 }, size: { width: 150, height: 60 }, label: 'target',
      ports: [{ id: 'dst.in', side: 'left', type: 'input' }] },
  ];
  edges: any[] = [];

  private readonly summary: Record<string, (p: any) => string> = {
    'connection:start': (p) => p?.sourcePort?.id ?? '?',
    'connection:update': (p) => `${p?.targetPort?.id ?? '(none)'} ${p?.isValid ? 'ok' : 'no'}`,
    'connection:port-enter': (p) => `${p?.port?.id ?? '?'} ${p?.isValid ? 'ok' : '✗ ' + (p?.rejectionReason ?? '')}`,
    'connection:port-leave': (p) => p?.port?.id ?? '?',
    'connection:complete': (p) => `${p?.sourcePortId ?? '?'} → ${p?.targetPortId ?? '?'}`,
    'connection:cancel': (p) => `${p?.sourcePort?.id ?? '?'} (abandoned / refused)`,
  };

  ngAfterViewInit() {
    const engine = this.canvas().activeEngine() as any;
    const logEl = this.log().nativeElement;
    const flagEls = new Map<string, HTMLElement>(
      Array.from(this.flags().nativeElement.querySelectorAll<HTMLElement>('.flag')).map((el) => [el.dataset['ev']!, el]));

    const light = (name: string) => {
      const el = flagEls.get(name); if (!el) return;
      el.style.opacity = '1'; el.style.fontWeight = '600';
      clearTimeout((el as any)._t);
      (el as any)._t = setTimeout(() => { el.style.opacity = '.32'; el.style.fontWeight = ''; }, 1100);
    };
    const logRow = (name: string, payload: any) => {
      const first = logEl.firstElementChild as HTMLElement | null;
      if (first && first.tagName === 'SPAN') first.remove();
      const row = document.createElement('div');
      row.className = 'row';
      const summary = (this.summary[name] ?? (() => ''))(payload);
      row.innerHTML = `<span style="display:inline-block;min-width:168px;font-weight:600"></span><span></span>`;
      (row.children[0] as HTMLElement).textContent = name;
      (row.children[1] as HTMLElement).textContent = summary;
      logEl.prepend(row);
      while (logEl.querySelectorAll('.row').length > 12) logEl.querySelector('.row:last-child')!.remove();
    };

    if (engine?.eventBus) {
      for (const name of Object.keys(this.summary)) {
        engine.eventBus.on(name, (payload: any) => { light(name); logRow(name, payload); });
      }
    }
    this.clear().nativeElement.addEventListener('click', () => {
      logEl.innerHTML = '<span style="opacity:.5">— log cleared —</span>';
    });
    markReady();
  }
}

interaction/context-menu.text:
import { AfterViewInit, Component, ElementRef, viewChild } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/renderer-angular';
import { markReady } from '../demo-ready';

/** Right-click a node → a menu opens anchored at the pointer, and every item
 *  mutates the node it names: Rename (setMetadata), Duplicate (engine.addNode),
 *  Delete (removeNode). Driven by a real contextmenu event. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  template: `
    <div #wrap style="height:100vh;position:relative">
      <grafloria-diagram-canvas [(nodes)]="nodes" [(edges)]="edges" style="display:block;height:100%" />
      <div #menu style="position:absolute;z-index:10;min-width:160px;background:var(--mbg,#1a1a1a);color:#fff;border:1px solid rgba(127,127,127,.35);border-radius:8px;box-shadow:0 8px 30px rgba(0,0,0,.18);padding:4px;display:none;font:13px system-ui,sans-serif">
        <button data-act="rename" style="display:block;width:100%;text-align:left;padding:7px 10px;border:0;background:transparent;color:inherit;border-radius:5px;cursor:pointer">Rename</button>
        <button data-act="duplicate" style="display:block;width:100%;text-align:left;padding:7px 10px;border:0;background:transparent;color:inherit;border-radius:5px;cursor:pointer">Duplicate</button>
        <button data-act="delete" style="display:block;width:100%;text-align:left;padding:7px 10px;border:0;background:transparent;color:inherit;border-radius:5px;cursor:pointer">Delete</button>
      </div>
    </div>
  `,
})
export class ContextMenuComponent implements AfterViewInit {
  canvas = viewChild.required(DiagramCanvasComponent);
  wrap = viewChild.required<ElementRef<HTMLElement>>('wrap');
  menu = viewChild.required<ElementRef<HTMLElement>>('menu');
  nodes: any[] = [
    { id: 'a', position: { x: 120, y: 120 }, size: { width: 120, height: 48 }, label: 'Alpha' },
    { id: 'b', position: { x: 380, y: 120 }, size: { width: 120, height: 48 }, label: 'Beta' },
  ];
  edges: any[] = [{ id: 'e', source: 'a', target: 'b' }];

  ngAfterViewInit() {
    const engine = this.canvas().activeEngine() as any;
    const model = engine?.getDiagram();
    const wrap = this.wrap().nativeElement;
    const menu = this.menu().nativeElement;
    let target: string | null = null;
    if (!model) { markReady(); return; }

    wrap.addEventListener('contextmenu', (e) => {
      const el = (e.target as HTMLElement).closest('[data-node-id]');
      if (!el) return;
      e.preventDefault();
      target = el.getAttribute('data-node-id');
      const rect = wrap.getBoundingClientRect();
      menu.style.left = `${e.clientX - rect.left}px`;
      menu.style.top = `${e.clientY - rect.top}px`;
      menu.style.display = 'block';
    });

    const act = async (action: string) => {
      const id = target; if (!id) return;
      if (action === 'rename') model.getNode(id)?.setMetadata('label', 'RENAMED');
      if (action === 'delete') model.removeNode(id);
      if (action === 'duplicate') {
        const s = model.getNode(id); if (!s) return;
        const copy = await engine.addNode({ type: 'rect', position: { x: s.position.x + 30, y: s.position.y + 60 }, size: { ...s.size } });
        copy.setMetadata('label', (s.getMetadata('label') ?? '') + ' copy');
      }
      menu.style.display = 'none';
    };
    for (const btn of Array.from(menu.querySelectorAll<HTMLButtonElement>('button'))) {
      btn.addEventListener('click', () => act(btn.dataset['act']!));
    }
    document.addEventListener('pointerdown', (e) => { if (!menu.contains(e.target as Node)) menu.style.display = 'none'; });
    document.addEventListener('keydown', (e) => { if (e.key === 'Escape') menu.style.display = 'none'; });
    markReady();
  }
}

interaction/contextual-zoom.text:
import { AfterViewInit, Component, ElementRef, viewChild } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/renderer-angular';
import { markReady } from '../demo-ready';

/** Level-of-detail: the detail the renderer draws follows the zoom. Zoom in for
 *  full labels; zoom out and the renderer sheds detail. The readout reports the
 *  zoom and how much label text reaches the DOM — genuinely different renders. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  template: `
    <div style="display:flex;gap:8px;padding:10px 24px;border-bottom:1px solid rgba(127,127,127,.25);align-items:center">
      <span>zoom:</span>
      <button (click)="setZoom(1.5)" style="padding:5px 12px;border-radius:6px;border:1px solid rgba(127,127,127,.4);background:transparent;color:inherit;cursor:pointer">1.5× high</button>
      <button (click)="setZoom(0.7)" style="padding:5px 12px;border-radius:6px;border:1px solid rgba(127,127,127,.4);background:transparent;color:inherit;cursor:pointer">0.7× medium</button>
      <button (click)="setZoom(0.3)" style="padding:5px 12px;border-radius:6px;border:1px solid rgba(127,127,127,.4);background:transparent;color:inherit;cursor:pointer">0.3× sketch</button>
      <button (click)="setZoom(0.15)" style="padding:5px 12px;border-radius:6px;border:1px solid rgba(127,127,127,.4);background:transparent;color:inherit;cursor:pointer">0.15× low</button>
      <span #readout style="margin-left:auto;font:12px/1.4 ui-monospace,monospace;opacity:.85"></span>
    </div>
    <div #host style="height:calc(100vh - 52px)">
      <grafloria-diagram-canvas [(nodes)]="nodes" [(edges)]="edges" style="display:block;height:100%" />
    </div>
  `,
})
export class ContextualZoomComponent implements AfterViewInit {
  canvas = viewChild.required(DiagramCanvasComponent);
  readout = viewChild.required<ElementRef<HTMLElement>>('readout');
  host = viewChild.required<ElementRef<HTMLElement>>('host');
  nodes: any[] = Array.from({ length: 12 }, (_, i) => ({
    id: `n${i}`, position: { x: (i % 4) * 200, y: Math.floor(i / 4) * 140 },
    size: { width: 150, height: 70 }, label: `Node ${i}`,
  }));
  edges: any[] = Array.from({ length: 11 }, (_, i) => ({ id: `e${i}`, source: `n${i}`, target: `n${i + 1}`, type: 'direct' }));

  ngAfterViewInit() {
    this.canvas().fitToContent(40);
    this.setZoom(1.5);
    markReady();
  }

  setZoom(z: number) {
    const vp = this.canvas().viewportController();
    vp?.setZoom(z);
    const texts = this.host().nativeElement.querySelectorAll('svg text').length;
    const el = this.readout()?.nativeElement;
    if (el) el.textContent = `zoom ${z}×  →  ${texts} text nodes in the DOM`;
  }
}

interaction/copy-paste.text:
import { AfterViewInit, Component, ElementRef, viewChild } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/renderer-angular';
import { markReady } from '../demo-ready';

/** Copy a node to the engine clipboard, then paste independent copies — each
 *  gets its own id and position, and mutating one leaves the others untouched.
 *  ⌘C / ⌘V drive the same engine.copy() / engine.paste() path. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  template: `
    <div #readout style="padding:8px 24px;font:12px/1.5 ui-monospace,monospace;opacity:.8;border-bottom:1px solid rgba(127,127,127,.25);white-space:pre"></div>
    <grafloria-diagram-canvas [(nodes)]="nodes" [(edges)]="edges" style="display:block;height:calc(100vh - 44px)" />
  `,
})
export class CopyPasteComponent implements AfterViewInit {
  canvas = viewChild.required(DiagramCanvasComponent);
  readout = viewChild.required<ElementRef<HTMLElement>>('readout');
  nodes: any[] = [
    { id: 'orig', position: { x: 120, y: 120 }, size: { width: 130, height: 50 }, label: 'Original' },
  ];
  edges: any[] = [];
  private key?: (e: KeyboardEvent) => void;

  async ngAfterViewInit() {
    const engine = this.canvas().activeEngine() as any;
    const model = engine?.getDiagram();
    const report = (m: string) => { const el = this.readout()?.nativeElement; if (el) el.textContent = m; };
    if (!engine || !model) { markReady(); return; }

    // Demonstrate the round trip on load: select, copy, paste one independent copy.
    engine.selectNodes(['orig']);
    await engine.copy();
    await engine.paste({ offset: { x: 60, y: 60 } });
    report(`copied Original; ${model.getNodes().length} nodes — ⌘C then ⌘V to make more`);

    this.key = (e: KeyboardEvent) => {
      if (!(e.metaKey || e.ctrlKey)) return;
      if (e.key === 'c') { engine.copy(); }
      if (e.key === 'v') {
        e.preventDefault();
        engine.paste({}).then(() => report(`${model.getNodes().length} nodes — each paste cascades to a new spot`));
      }
    };
    window.addEventListener('keydown', this.key);
    markReady();
  }
}

interaction/drag-and-drop.text:
import { AfterViewInit, Component, ElementRef, viewChild } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/renderer-angular';
import { markReady } from '../demo-ready';

/** Drag a chip out of the palette and drop it on the canvas: a node is created
 *  AT THE DROP POINT in world space (through the live viewport), so it lands
 *  under the cursor even after the camera has panned/zoomed. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  template: `
    <div style="display:grid;grid-template-columns:160px 1fr;height:100vh">
      <div style="border-right:1px solid rgba(127,127,127,.25);padding:12px;display:flex;flex-direction:column;gap:10px">
        <div class="chip" data-kind="source" draggable="true" style="padding:10px;border:1px dashed rgba(127,127,127,.5);border-radius:8px;text-align:center;cursor:grab;user-select:none;font:13px/1.2 system-ui,sans-serif">Source</div>
        <div class="chip" data-kind="filter" draggable="true" style="padding:10px;border:1px dashed rgba(127,127,127,.5);border-radius:8px;text-align:center;cursor:grab;user-select:none;font:13px/1.2 system-ui,sans-serif">Filter</div>
        <div class="chip" data-kind="sink" draggable="true" style="padding:10px;border:1px dashed rgba(127,127,127,.5);border-radius:8px;text-align:center;cursor:grab;user-select:none;font:13px/1.2 system-ui,sans-serif">Sink</div>
      </div>
      <div #host style="height:100%;position:relative">
        <grafloria-diagram-canvas [(nodes)]="nodes" [(edges)]="edges" style="display:block;height:100%" />
        <span #readout style="position:absolute;right:10px;top:8px;font:12px/1.4 ui-monospace,monospace;opacity:.75"></span>
      </div>
    </div>
  `,
})
export class DragAndDropComponent implements AfterViewInit {
  canvas = viewChild.required(DiagramCanvasComponent);
  host = viewChild.required<ElementRef<HTMLElement>>('host');
  readout = viewChild.required<ElementRef<HTMLElement>>('readout');
  nodes: any[] = [];
  edges: any[] = [];

  async ngAfterViewInit() {
    const engine = this.canvas().activeEngine() as any;
    const model = engine?.getDiagram();
    const host = this.host().nativeElement;
    const vp = this.canvas().viewportController();
    if (!engine || !model || !vp) { markReady(); return; }

    const report = () => { const el = this.readout()?.nativeElement; if (el) el.textContent = `${model.getNodes().length} nodes`; };
    const dropAt = async (kind: string, clientX: number, clientY: number) => {
      const w = vp.clientToWorld(clientX, clientY, host.getBoundingClientRect());
      const node = await engine.addNode({ type: 'rect', position: { x: w.x - 55, y: w.y - 22 }, size: { width: 110, height: 44 } });
      node.data = { kind };
      node.setMetadata('label', kind);
      report();
      return node;
    };

    // Seed two dropped nodes so the result of the gesture is visible on load.
    const r = host.getBoundingClientRect();
    await dropAt('filter', r.left + r.width * 0.4, r.top + r.height * 0.4);
    await dropAt('sink', r.left + r.width * 0.6, r.top + r.height * 0.6);

    // Live HTML5 drag-and-drop for a human visitor.
    let dragKind: string | null = null;
    for (const chip of Array.from(host.ownerDocument.querySelectorAll<HTMLElement>('.chip'))) {
      chip.addEventListener('dragstart', () => { dragKind = chip.dataset['kind'] ?? null; });
    }
    host.addEventListener('dragover', (e) => e.preventDefault());
    host.addEventListener('drop', (e) => { e.preventDefault(); if (dragKind) dropAt(dragKind, e.clientX, e.clientY); });
    markReady();
  }
}

