import { AfterViewInit, Component, viewChild } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/renderer-angular';
import { markReady } from '../demo-ready';

/** Proximity connect wired into the ENGINE: drag a node next to another and the
 *  engine's own drag path proposes AND commits the wire — the page only sets
 *  enableProximityConnect. The auto-created link is a single undoable step. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  template: `
    <grafloria-diagram-canvas [(nodes)]="nodes" [(edges)]="edges"
      [enableProximityConnect]="true" style="display:block;height:100vh" />
  `,
})
export class ProximityConnectLiveComponent implements AfterViewInit {
  canvas = viewChild.required(DiagramCanvasComponent);
  nodes: any[] = [
    { id: 'a', position: { x: 150, y: 150 }, size: { width: 150, height: 80 }, label: 'drag me →' },
    { id: 'b', position: { x: 600, y: 150 }, size: { width: 150, height: 80 }, label: 'B' },
  ];
  edges: any[] = [];

  ngAfterViewInit() {
    this.canvas().activeEngine()?.setInteractionConfig({ enableProximityConnect: true } as never);
    markReady();
  }
}

interaction/touch-device.text:
import { AfterViewInit, Component } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/renderer-angular';
import { markReady } from '../demo-ready';

/** Real finger input: one finger pans, one finger on a node drags it, a tap
 *  selects, and two fingers pinch-zoom — all through the same touch pipeline a
 *  phone uses. touch-action:none keeps the browser from eating the gesture. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  template: `
    <div style="padding:8px 24px;font:12px/1.5 ui-monospace,monospace;opacity:.85;border-bottom:1px solid rgba(127,127,127,.25)">drive with a finger: pan, pinch, tap, drag</div>
    <grafloria-diagram-canvas [(nodes)]="nodes" [(edges)]="edges"
      style="display:block;height:calc(100vh - 40px);touch-action:none" />
  `,
})
export class TouchDeviceComponent implements AfterViewInit {
  nodes: any[] = [
    { id: 'a', position: { x: 500, y: 120 }, size: { width: 120, height: 60 }, label: 'A' },
    { id: 'b', position: { x: 500, y: 320 }, size: { width: 120, height: 60 }, label: 'B' },
  ];
  edges: any[] = [];
  ngAfterViewInit() { markReady(); }
}

interaction/validation.text:
import { AfterViewInit, Component, OnDestroy, viewChild } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/renderer-angular';
import { registerConnectionValidator, clearConnectionValidators } from '@grafloria/renderer';
import { markReady } from '../demo-ready';

/** A typed graph — sources, transforms, sinks — with a registered validator:
 *  nothing flows OUT of a Sink, so a connection whose source is a sink is
 *  refused (with a reason) while the legal ones connect. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  template: `
    <div style="padding:8px 24px;font:12px/1.5 ui-monospace,monospace;opacity:.8;border-bottom:1px solid rgba(127,127,127,.25)">validator registered: a Sink may not be a connection source</div>
    <grafloria-diagram-canvas [(nodes)]="nodes" [(edges)]="edges" style="display:block;height:calc(100vh - 40px)" />
  `,
})
export class ValidationComponent implements AfterViewInit, OnDestroy {
  canvas = viewChild.required(DiagramCanvasComponent);
  nodes: any[] = [
    { id: 'src', position: { x: 80, y: 80 }, size: { width: 120, height: 46 }, label: 'Source', data: { role: 'source' } },
    { id: 'xf', position: { x: 320, y: 80 }, size: { width: 120, height: 46 }, label: 'Transform', data: { role: 'transform' } },
    { id: 'sink', position: { x: 560, y: 80 }, size: { width: 120, height: 46 }, label: 'Sink', data: { role: 'sink' } },
  ];
  edges: any[] = [];
  private dispose?: () => void;

  ngAfterViewInit() {
    clearConnectionValidators();
    this.dispose = registerConnectionValidator(({ sourceNode }: any) => {
      if (sourceNode?.data?.role === 'sink') return 'A Sink has no outputs';
      return true;
    }) as any;
    this.canvas().activeEngine()?.setInteractionConfig({ portVisibility: 'always' as never });
    markReady();
  }

  ngOnDestroy() { this.dispose?.(); clearConnectionValidators(); }
}
